// Crypto Tax Edge v5.0 — Multi-platform | Noves + Claude dual-source
(function () {
  'use strict';
  console.log('[CTE] content.js loaded on', window.location.hostname);

  const CTE_PANEL_ID = 'cte-panel';

  // ── Logo (base64 embedded) ───────────────────────────────────────────────
  const LOGO_B64 = '';
  const LOGO_SRC = `data:image/png;base64,${LOGO_B64}`;
  const ICON_SRC = 'data:image/png;base64,';

  // ── Platform detection ───────────────────────────────────────────────────
  const PLATFORMS = {
    'app.koinly.io':         { name: 'Koinly',           color: '#00b47e' },
    'cointracker.io':        { name: 'CoinTracker',      color: '#5b6ef5' },
    'app.cointracker.io':    { name: 'CoinTracker',      color: '#5b6ef5' },
    'taxbit.com':            { name: 'TaxBit',           color: '#1a73e8' },
    'app.taxbit.com':        { name: 'TaxBit',           color: '#1a73e8' },
    'coinpanda.io':          { name: 'Coinpanda',        color: '#ff6b35' },
    'app.coinpanda.io':      { name: 'Coinpanda',        color: '#ff6b35' },
    'zenledger.io':          { name: 'ZenLedger',        color: '#7c3aed' },
    'app.zenledger.io':      { name: 'ZenLedger',        color: '#7c3aed' },
    'cryptotrader.tax':      { name: 'CryptoTrader.Tax', color: '#0ea5e9' },
    'app.cryptotrader.tax':  { name: 'CryptoTrader.Tax', color: '#0ea5e9' },
    'cointracking.info':     { name: 'CoinTracking',     color: '#f59e0b' },
    'app.breezing.io':       { name: 'Breezing',         color: '#6366f1' },
    'breezing.io':           { name: 'Breezing',         color: '#6366f1' },
    'cryptio.co':            { name: 'Cryptio',          color: '#0d9488' },
    'app.cryptio.co':        { name: 'Cryptio',          color: '#0d9488' },
    'cryptoworth.com':       { name: 'Cryptoworth',      color: '#8b5cf6' },
    'app.cryptoworth.com':   { name: 'Cryptoworth',      color: '#8b5cf6' },
    'tres.finance':          { name: 'Tres Finance',     color: '#10b981' },
    'app.tres.finance':      { name: 'Tres Finance',     color: '#10b981' },
    'tokentax.co':           { name: 'TokenTax',         color: '#f97316' },
    'app.tokentax.co':       { name: 'TokenTax',         color: '#f97316' },
    'divly.com':             { name: 'Divly',            color: '#ec4899' },
    'app.divly.com':         { name: 'Divly',            color: '#ec4899' },
    'accointing.com':        { name: 'Accointing',       color: '#3b82f6' },
    'app.accointing.com':    { name: 'Accointing',       color: '#3b82f6' },
    'koinx.com':             { name: 'KoinX',            color: '#f59e0b' },
    'app.koinx.com':         { name: 'KoinX',            color: '#f59e0b' },
  };

  function getCurrentPlatform() {
    const host = window.location.hostname.replace(/^www\./, '');
    return PLATFORMS[host] || { name: host, color: '#64748b' };
  }

  // ── Chain metadata ───────────────────────────────────────────────────────
  const CHAIN_META = {
    ethereum: { name: 'Ethereum', icon: '⟠', color: '#627EEA', explorer: 'https://etherscan.io/tx/' },
    polygon:  { name: 'Polygon',  icon: '⬡', color: '#8247E5', explorer: 'https://polygonscan.com/tx/' },
    base:     { name: 'Base',     icon: '🔵', color: '#0052FF', explorer: 'https://basescan.org/tx/' },
    arbitrum: { name: 'Arbitrum', icon: '🔷', color: '#28A0F0', explorer: 'https://arbiscan.io/tx/' },
    optimism: { name: 'Optimism', icon: '🔴', color: '#FF0420', explorer: 'https://optimistic.etherscan.io/tx/' },
    bsc:      { name: 'BSC',      icon: '🟡', color: '#F3BA2F', explorer: 'https://bscscan.com/tx/' },
    solana:   { name: 'Solana',   icon: '◎',  color: '#9945FF', explorer: 'https://solscan.io/tx/' },
  };

  const TYPE_META = {
    swap: { icon: '↔', color: '#00b8ff' }, trade: { icon: '↔', color: '#00b8ff' },
    exchange: { icon: '↔', color: '#00b8ff' }, transfer: { icon: '→', color: '#94a3b8' },
    send: { icon: '→', color: '#94a3b8' }, receive: { icon: '←', color: '#94a3b8' },
    deposit: { icon: '↓', color: '#00d4b8' }, withdraw: { icon: '↑', color: '#f0a500' },
    stake: { icon: '⚑', color: '#a855f7' }, unstake: { icon: '⚐', color: '#c084fc' },
    addliquidity: { icon: '+', color: '#34d399' }, removeliquidity: { icon: '-', color: '#00d4b8' },
    liquidityin: { icon: '+', color: '#34d399' }, liquidityout: { icon: '-', color: '#00d4b8' },
    addtopool: { icon: '⬇', color: '#a855f7' }, removefrompool: { icon: '⬆', color: '#c084fc' },
    claim: { icon: '★', color: '#fbbf24' }, claimreward: { icon: '★', color: '#fbbf24' },
    reward: { icon: '★', color: '#fbbf24' }, stakingreward: { icon: '★', color: '#fbbf24' },
    mint: { icon: '◈', color: '#fb923c' }, nftmint: { icon: '◈', color: '#fb923c' },
    wrap: { icon: '⊛', color: '#94a3b8' }, unwrap: { icon: '⊙', color: '#94a3b8' },
    approve: { icon: '✓', color: '#475569' }, bridge: { icon: '⇌', color: '#38bdf8' },
    borrow: { icon: '↙', color: '#fb7185' }, repay: { icon: '↗', color: '#4ade80' },
    liquidation: { icon: '⚡', color: '#ef4444' }, failed: { icon: '✗', color: '#ef4444' },
    unknown: { icon: '?', color: '#6b7280' },
  };

  function getTypeMeta(t) {
    const k = (t || '').toLowerCase().replace(/[^a-z]/g, '');
    return TYPE_META[k] || TYPE_META.unknown;
  }

  // ── Tier / auth helpers ──────────────────────────────────────────────────
  // tier: 'free' | 'starter' | 'pro' | 'cpa'
  // Free tier: tx type label visible, all detail blurred + upgrade CTA
  function getUserTier() {
    return new Promise(resolve => {
      chrome.storage.local.get(['userTier', 'authToken'], data => {
        // If they have a saved auth token, use their tier; fallback to free
        resolve(data.userTier || 'anonymous');
      });
    });
  }

  // ── Background message bridge ────────────────────────────────────────────
  function bgMessage(payload) {
    return new Promise((resolve, reject) => {
      chrome.runtime.sendMessage(payload, (response) => {
        if (chrome.runtime.lastError) reject(new Error(chrome.runtime.lastError.message));
        else resolve(response);
      });
    });
  }

  // ── Main analyze ─────────────────────────────────────────────────────────
  async function analyzeTx(hash) {
    hash = hash.trim();
    showLoading('Querying Noves…');

    try {
      // Key handled by background worker — users with saved key get priority,
      // otherwise background uses the platform key if configured
      const tier = await getUserTier();
      const [response] = await Promise.all([
        bgMessage({ action: 'analyze_tx', hash, tier }),
      ]);

      if (response.error) {
        if (response.error === 'QUOTA_EXCEEDED') {
          showQuotaOverlay(response.tier, response.limit);
        } else {
          showError(response.error);
        }
        return;
      }
      renderResult(hash, response, tier);
    } catch (e) {
      showError('Extension error: ' + e.message);
    }
  }

  // ── Render result (v6 — deduplicated, prioritized layout) ──────────────────
  function renderResult(hash, result, tier) {
    const container = document.getElementById('cte-result');
    if (!container) return;

    const { chain, novesData, rawTx,
            txType, confidence, koinlyAction, reasoning,
            taxable, taxCategory, source, needsReview,
            disagreement, sourceBreakdown, claudeError } = result;

    // ── Usage counter banner (shows at 70%+ quota) ──────────────
    chrome.storage.local.get(['cte_anon_used', 'cte_monthly_used', 'cte_month_key', 'userTier'], function(s) {
      const nowMonth = new Date().toISOString().slice(0,7);
      const tier_ = s.userTier || 'anonymous';
      const LIMITS_ = { anonymous: 10, free: 25, starter: 300, pro: 1000, cpa: Infinity, admin: Infinity };
      const limit_ = LIMITS_[tier_] || 10;
      const used_ = tier_ === 'anonymous'
        ? (s.cte_anon_used || 0)
        : ((s.cte_month_key === nowMonth) ? (s.cte_monthly_used || 0) : 0);
      const pct = used_ / limit_;
      if (pct >= 0.7 && limit_ !== Infinity) {
        const remaining = limit_ - used_;
        const isAnon = tier_ === 'anonymous';
        const banner = document.createElement('div');
        banner.style.cssText = 'margin-top:10px;padding:8px 10px;background:rgba(251,191,36,0.1);border:1px solid rgba(251,191,36,0.3);border-radius:8px;font-size:10px;color:#fbbf24;text-align:center;';
        banner.innerHTML = isAnon
          ? `⚠ <b>${remaining} trial ${remaining === 1 ? 'analysis' : 'analyses'} left</b> — <a href="https://cryptotaxedge.com/#signup" target="_blank" style="color:#00c9b1;text-decoration:underline">Sign up free for 25/month →</a>`
          : `⚠ <b>${remaining} ${tier_} ${remaining === 1 ? 'analysis' : 'analyses'} left this month</b> — <a href="https://cryptotaxedge.com/#pricing" target="_blank" style="color:#00c9b1;text-decoration:underline">Upgrade →</a>`;
        container.appendChild(banner);
      }
    });

    const isFree = false; // All tiers see full analysis — throttle on usage, not content
    const chainMeta  = CHAIN_META[chain] || { name: chain, color: '#6b7280', icon: '?', explorer: '' };
    const typeMeta   = getTypeMeta(txType);
    const explorerUrl = chainMeta.explorer + hash;

    const c        = (novesData || {}).classificationData || {};
    const protocol = c.protocol?.name || novesData?.protocol || '';
    const sent     = c.sent     || novesData?.sent     || [];
    const received = c.received || novesData?.received || [];

    const nConf = sourceBreakdown?.noves || 0;
    const cConf = sourceBreakdown?.claude || 0;
    const hasRawLogs = rawTx && rawTx.logCount > 0;
    const confColor  = confidence >= 85 ? '#00d4b8' : confidence >= 65 ? '#fbbf24' : '#f87171';

    // Source badge (compact — one place only)
    const sourceBadge = (() => {
      if (source === 'noves+claude★') return { bg: 'rgba(0,212,184,0.15)', color: '#00d4b8', border: 'rgba(0,212,184,0.3)', label: '★ dual-source' };
      if (source === 'noves+claude⚠') return { bg: 'rgba(251,191,36,0.12)', color: '#fbbf24', border: 'rgba(251,191,36,0.3)', label: '⚠ review' };
      if (source === 'noves+claude')  return { bg: 'rgba(0,212,184,0.10)', color: '#00d4b8', border: 'rgba(0,212,184,0.25)', label: '✓ confirmed' };
      return { bg: 'rgba(107,114,128,0.1)', color: '#6b7280', border: 'rgba(107,114,128,0.25)', label: 'noves only' };
    })();

    // ── Build asset rows ─────────────────────────────────────────────────────
    function buildAssetRows(assets, dir) {
      return assets.map(a => {
        const amt   = a.amount || a.value || '';
        const token = a.token?.symbol || a.asset || a.currency || a.symbol || '';
        const usd   = a.token?.price?.usd ? ` ≈ $${(parseFloat(amt) * a.token.price.usd).toFixed(2)}` : '';
        const arrow = dir === 'sent' ? '↑' : '↓';
        const col   = dir === 'sent' ? '#f87171' : '#4ade80';
        return `<div class="cte-asset-row">
          <span style="color:${col};font-weight:700;font-size:11px">${arrow}</span>
          <span class="cte-asset-amt">${amt} ${token}</span>
          ${usd ? `<span class="cte-asset-usd">${usd}</span>` : ''}
        </div>`;
      }).join('');
    }

    const hasSent     = sent.length > 0;
    const hasReceived = received.length > 0;
    const hasAssets   = hasSent || hasReceived;

    const assetsHTML = hasAssets ? `
      <div class="cte-assets-grid">
        ${hasSent ? `<div class="cte-assets-col">
          <div class="cte-assets-col-label" style="color:#f87171">Sent</div>
          ${buildAssetRows(sent, 'sent')}
        </div>` : ''}
        ${hasReceived ? `<div class="cte-assets-col">
          <div class="cte-assets-col-label" style="color:#4ade80">Received</div>
          ${buildAssetRows(received, 'received')}
        </div>` : ''}
      </div>` : '';

    // ── Taxable pill ─────────────────────────────────────────────────────────
    const taxPill = taxCategory && taxCategory !== 'unknown' ? `
      <span class="cte-tax-pill" style="background:${taxable ? 'rgba(248,113,113,0.12)' : 'rgba(74,222,128,0.12)'};color:${taxable ? '#f87171' : '#4ade80'};border-color:${taxable ? 'rgba(248,113,113,0.35)' : 'rgba(74,222,128,0.35)'}">
        ${taxable ? '⚡ Taxable' : '✓ Non-taxable'} — ${taxCategory}
      </span>` : '';

    // ── Disagreement notice ──────────────────────────────────────────────────
    const disagreeHTML = (needsReview && disagreement) ? `
      <div class="cte-disagree-box">
        <div class="cte-disagree-title">⚠ Sources Disagree — Review Required</div>
        <div style="font-size:10px;color:#6b7280;margin-top:3px">
          Noves: <span style="color:#3b82f6">${disagreement.novesType}</span> → ${disagreement.novesKoinly}
          &nbsp;·&nbsp;
          Claude: <span style="color:#00d4b8">${disagreement.claudeType}</span> → ${disagreement.claudeKoinly}
        </div>
      </div>` : '';

    // ── Detail HTML (blurred for free tier) ──────────────────────────────────
    const detailHTML = `
      ${disagreeHTML}

      <!-- ① AI Explanation — first, prominent -->
      ${reasoning ? `<div class="cte-explanation">
        <span class="cte-explanation-icon">🤖</span>
        <span class="cte-explanation-text">${reasoning}</span>
      </div>` : ''}

      <!-- ② Assets moved — sent/received side by side -->
      ${hasAssets ? `<div class="cte-section">
        <div class="cte-section-label">Assets Moved</div>
        ${assetsHTML}
      </div>` : ''}

      <!-- ③ Tax classification — single pill, no duplication -->
      ${taxPill ? `<div style="margin:7px 0">${taxPill}</div>` : ''}

      <!-- ④ Confidence + source — one compact row -->
      <div class="cte-conf-row">
        <span class="cte-conf-label">Confidence</span>
        <div class="cte-conf-bar-wrap">
          <div class="cte-conf-fill" style="width:${confidence}%;background:${confColor}"></div>
        </div>
        <span class="cte-conf-num" style="color:${confColor}">${confidence}%</span>
        <span class="cte-source-badge" style="background:${sourceBadge.bg};color:${sourceBadge.color};border-color:${sourceBadge.border}">${sourceBadge.label}</span>
      </div>

      <!-- Koinly tag -->
      <div class="cte-koinly-box">
        <span class="cte-koinly-label">📌</span>
        <span class="cte-koinly-text">${koinlyAction || 'Manual review needed'}</span>
      </div>

      <!-- Claude not used notice -->
      ${claudeError && source === 'noves' ? `
      <div style="font-size:10px;color:#6b7280;padding:5px 8px;background:rgba(255,255,255,0.02);border-radius:6px;border:1px solid rgba(255,255,255,0.06)">
        Noves only — ${claudeError.includes('key') ? 'add Anthropic key in settings' : claudeError.slice(0, 60)}
      </div>` : ''}

      <!-- Raw toggle -->
      <div class="cte-raw-toggle" id="cte-raw-toggle">
        <span>{ } Raw Noves data</span><span id="cte-arrow">▶</span>
      </div>
      <div class="cte-raw-data" id="cte-raw-data" style="display:none">
        <pre class="cte-raw-pre">${JSON.stringify(novesData, null, 2).replace(/</g, '&lt;').replace(/>/g, '&gt;')}</pre>
      </div>
    `;

    // Free tier gate
    const detailSection = isFree
      ? `<div class="cte-blur-gate">
           <div class="cte-blur-content">${detailHTML}</div>
           <div class="cte-upgrade-overlay">
             <div class="cte-upgrade-icon">🔒</div>
             <div class="cte-upgrade-title">Upgrade to see full analysis</div>
             <div class="cte-upgrade-sub">Free plan shows TX type only. Upgrade for Koinly tags, confidence scores, assets & tax guidance.</div>
             <button class="cte-upgrade-btn" onclick="window.open('https://cryptotaxedge.com','_blank')">
               Upgrade — from $49/mo
             </button>
           </div>
         </div>`
      : detailHTML;

    container.innerHTML = `
      <div class="cte-result-card">

        <!-- Chain + explorer header -->
        <div class="cte-result-top">
          <span class="cte-chain-badge" style="border-color:${chainMeta.color};color:${chainMeta.color}">
            ${chainMeta.icon} ${chainMeta.name}
          </span>
          <div style="display:flex;align-items:center;gap:6px">
            ${hasRawLogs ? '<span style="font-size:9px;color:#00d4b8;background:rgba(0,212,184,0.08);border:1px solid rgba(0,212,184,0.2);border-radius:4px;padding:1px 5px">⛓ raw logs</span>' : ''}
            <a href="${explorerUrl}" target="_blank" class="cte-explorer-link">Explorer ↗</a>
          </div>
        </div>

        <!-- TX type block -->
        <div class="cte-action-block" style="border-color:${typeMeta.color}33;background:${typeMeta.color}0d">
          <div class="cte-action-icon" style="color:${typeMeta.color}">${typeMeta.icon}</div>
          <div style="flex:1">
            <div style="display:flex;align-items:center;gap:7px;flex-wrap:wrap">
              <span class="cte-action-type" style="color:${typeMeta.color}">${capitalize(txType)}</span>
              ${needsReview ? '<span style="font-size:9px;font-weight:700;background:rgba(251,191,36,0.15);color:#fbbf24;border:1px solid rgba(251,191,36,0.3);border-radius:4px;padding:1px 6px">⚠ REVIEW</span>' : ''}
              ${isFree ? '<span style="font-size:9px;background:rgba(0,212,184,0.1);color:#00d4b8;border:1px solid rgba(0,212,184,0.2);border-radius:4px;padding:1px 5px">FREE</span>' : ''}
              ${!isFree ? `<div class="cte-feedback-row" id="cte-feedback" style="margin-left:auto">
                <span class="cte-feedback-label">Correct?</span>
                <button class="cte-thumb" id="cte-thumb-up" title="Correct">👍</button>
                <button class="cte-thumb" id="cte-thumb-down" title="Incorrect">👎</button>
              </div>` : ''}
            </div>
            ${protocol ? `<div class="cte-action-protocol">via ${protocol}</div>` : ''}
          </div>
        </div>

        ${detailSection}

        <!-- TX hash row -->
        <div class="cte-bottom-row">
          <div class="cte-hash-row">
            <span class="cte-hash-label">TX</span>
            <span class="cte-hash-val">${hash.slice(0, 20)}…</span>
          </div>
        </div>

      </div>
    `;

    // Wire up raw toggle
    if (!isFree) {
      document.getElementById('cte-raw-toggle')?.addEventListener('click', () => {
        const raw   = document.getElementById('cte-raw-data');
        const arrow = document.getElementById('cte-arrow');
        const open  = raw.style.display === 'none';
        raw.style.display = open ? 'block' : 'none';
        arrow.textContent = open ? '▼' : '▶';
      });

      // Wire up feedback buttons
      function sendVote(vote) {
        const feedbackEl = document.getElementById('cte-feedback');
        if (feedbackEl) {
          feedbackEl.innerHTML = `<span style="font-size:10px;color:#00d4b8">${vote === 'up' ? '👍 Thanks!' : '👎 Noted — we\'ll improve'}</span>`;
        }
        chrome.storage.local.get(['userTier', 'userId'], function(s) {
          chrome.runtime.sendMessage({
            action: 'send_feedback',
            payload: {
              tx_hash:       hash,
              chain:         chain,
              tx_type:       txType,
              koinly_action: koinlyAction,
              tax_category:  taxCategory,
              taxable:       taxable,
              confidence:    confidence,
              source:        source,
              reasoning:     reasoning,
              vote:          vote,
              user_tier:     s.userTier || 'anonymous',
              user_id:       s.userId   || null,
            }
          });
        });
      }

      document.getElementById('cte-thumb-up')?.addEventListener('click',   () => sendVote('up'));
      document.getElementById('cte-thumb-down')?.addEventListener('click', () => sendVote('down'));
    }
  }

  function capitalize(s) {
    if (!s) return 'Unknown';
    return s.charAt(0).toUpperCase() + s.slice(1).toLowerCase();
  }

  // ── UI helpers ────────────────────────────────────────────────────────────
  function showLoading(msg) {
    const el = document.getElementById('cte-result');
    if (el) el.innerHTML = `
      <div class="cte-loading">
        <div class="cte-spinner"></div>
        <div>
          <div>${msg}</div>
          <div style="font-size:9px;color:#334155;margin-top:3px">Querying Noves + Claude in parallel…</div>
        </div>
      </div>`;
  }

  function showQuotaOverlay(tier, limit) {
    const container = document.getElementById('cte-result');
    if (!container) return;
    const isAnon = tier === 'anonymous';
    container.innerHTML = `
      <div style="position:relative;border-radius:10px;overflow:hidden;">
        <!-- Blurred ghost of a result card -->
        <div style="filter:blur(3px);opacity:0.4;pointer-events:none;padding:12px;">
          <div style="height:14px;background:#1e2870;border-radius:4px;margin-bottom:8px;"></div>
          <div style="height:10px;background:#1e2870;border-radius:4px;width:70%;margin-bottom:8px;"></div>
          <div style="height:10px;background:#1e2870;border-radius:4px;width:50%;margin-bottom:8px;"></div>
          <div style="height:10px;background:#1e2870;border-radius:4px;width:80%;"></div>
        </div>
        <!-- Overlay -->
        <div style="position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;background:rgba(14,19,64,0.85);border-radius:10px;padding:16px;text-align:center;border:1px solid rgba(0,201,177,0.3);">
          <div style="font-size:22px;margin-bottom:6px;">🔒</div>
          <div style="font-size:13px;font-weight:700;color:#e2e8f0;margin-bottom:4px;">
            ${isAnon ? 'Trial limit reached' : 'Monthly limit reached'}
          </div>
          <div style="font-size:10px;color:#8892c4;margin-bottom:12px;">
            ${isAnon
              ? 'You\'ve used all 10 free trial analyses'
              : 'You\'ve used all ' + limit + ' analyses this month'}
          </div>
          <a href="https://cryptotaxedge.com/#signup" target="_blank"
             style="display:block;width:100%;padding:8px;background:linear-gradient(135deg,#00c9b1,#3dd8f0);border-radius:7px;color:#0e1340;font-weight:700;font-size:12px;text-decoration:none;margin-bottom:6px;">
            ${isAnon ? 'Sign up free — 25 TX/month →' : 'Upgrade your plan →'}
          </a>
          ${isAnon ? '<div style="font-size:9px;color:#8892c4;">Already have an account? Open the extension to sign in.</div>' : ''}
        </div>
      </div>`;
  }

  function showError(msg) {
    const el = document.getElementById('cte-result');
    if (el) el.innerHTML = `<div class="cte-error">⚠ ${msg}</div>`;
  }

  // ── Panel ─────────────────────────────────────────────────────────────────
  function createPanel() {
    const platform = getCurrentPlatform();
    const el = document.createElement('div');
    el.id = CTE_PANEL_ID;
    el.innerHTML = `
      <div class="cte-header">
        <div class="cte-logo-row">
          <img class="cte-logo-img" src="data:image/png;base64," alt="Crypto Tax Edge" />
          <div class="cte-brand">
            <div class="cte-brand-name">Crypto <span>Tax Edge</span></div>
            <div class="cte-brand-sub">Powered by AI</div>
          </div>
        </div>
        <div style="display:flex;align-items:center;gap:6px">
          <span class="cte-platform-badge">${platform.name}</span>
          <button class="cte-btn-icon" id="cte-minimize" title="Close">×</button>
        </div>
      </div>
      <div id="cte-body">
        <div class="cte-tagline">Paste a tx hash for instant AI classification.</div>

        <div id="cte-key-row" style="margin-bottom:9px">
          <div style="display:flex;align-items:center;gap:8px;padding:7px 10px;background:rgba(0,212,184,0.07);border:1px solid rgba(0,212,184,0.2);border-radius:7px">
            <div style="width:7px;height:7px;border-radius:50%;background:#00d4b8;box-shadow:0 0 6px #00d4b8;flex-shrink:0"></div>
            <span style="font-size:10px;color:#00d4b8">Dual-Source AI Analysis Active</span>
          </div>
        </div>

        <div class="cte-input-row">
          <input id="cte-hash-input" type="text" placeholder="0x… or Solana signature" autocomplete="off" spellcheck="false" />
          <button id="cte-analyze-btn">Analyze</button>
        </div>

        <div class="cte-pills">
          <span class="cte-pill">⟠ ETH</span>
          <span class="cte-pill">⬡ MATIC</span>
          <span class="cte-pill">🔵 BASE</span>
          <span class="cte-pill">🔷 ARB</span>
          <span class="cte-pill">🔴 OP</span>
          <span class="cte-pill">🟡 BSC</span>
          <span class="cte-pill">◎ SOL</span>
        </div>

        <div id="cte-result"></div>

        <div class="cte-footer">
          cryptotaxedge.com · Noves + Claude
        </div>
      </div>
    `;
    return el;
  }

  // ── Row injection ─────────────────────────────────────────────────────────
  const CTE_ROW_BTN = 'cte-row-btn';

  function extractHashFromRow(row) {
    const html = row.innerHTML || '';
    const hrefMatch = html.match(/href="[^"]*?(0x[a-fA-F0-9]{64})[^"]*?"/);
    if (hrefMatch) return hrefMatch[1];
    const fullMatch = html.match(/0x[a-fA-F0-9]{64}/);
    if (fullMatch) return fullMatch[0];
    const links = row.querySelectorAll('a[href]');
    for (const link of links) {
      const m = (link.getAttribute('href') || '').match(/\/tx\/(0x[a-fA-F0-9]{64})/);
      if (m) return m[1];
    }
    const solMatch = html.match(/\/tx\/([1-9A-HJ-NP-Za-km-z]{80,90})/);
    if (solMatch) return solMatch[1];
    return null;
  }

  function injectRowButtons() {
    const seen = new Set();
    document.querySelectorAll('*').forEach(el => {
      if (seen.has(el) || el.querySelector('.' + CTE_ROW_BTN)) return;
      if (el.offsetHeight < 30 || el.offsetWidth < 100) return;
      const html = el.innerHTML || '';
      const text = el.innerText || '';
      const hasHash = /0x[a-fA-F0-9]{40,}/.test(html)
                   || /href="[^"]*(?:scan\.com|scan\.io|etherscan|polygonscan|basescan|arbiscan|solscan)[^"]*\/tx\//.test(html);
      const hasTx  = /(Deposit|Send|Receive|Withdraw|Trade|Transfer|Swap)/i.test(text);
      const hasAmt = /(MATIC|ETH|USDC|BTC|SOL|BNB|DAI|USDT)/i.test(text) || /[+\-]\s*[\d,]+(\.\d+)?/.test(text);
      if (!hasHash || !hasTx || !hasAmt) return;
      const childQualifies = [...el.children].some(child => {
        const ch = child.innerHTML || '';
        return /0x[a-fA-F0-9]{40,}/.test(ch) && /(Deposit|Send|Receive|Withdraw|Trade|Transfer|Swap)/i.test(child.innerText || '');
      });
      if (childQualifies) return;
      seen.add(el);
      const hash = extractHashFromRow(el);
      if (!hash) return;

      const btn = document.createElement('button');
      btn.className = CTE_ROW_BTN;
      btn.title = 'Analyze with Crypto Tax Edge';
      btn.setAttribute('data-hash', hash);

      const img = document.createElement('img');
      img.src = ICON_SRC;
      img.alt = 'CTE';
      btn.appendChild(img);

      btn.addEventListener('click', e => {
        e.stopPropagation(); e.preventDefault();
        document.querySelectorAll('.cte-row-active').forEach(r => r.classList.remove('cte-row-active'));
        el.classList.add('cte-row-active');
        // Open panel and sync FAB state
        const panel = document.getElementById(CTE_PANEL_ID);
        const fab   = document.getElementById('cte-fab');
        if (panel) { panel.style.display = 'block'; }
        if (fab)   { fab.classList.add('cte-fab-active'); }
        const input = document.getElementById('cte-hash-input');
        if (input) input.value = hash;
        analyzeTx(hash);
      });

      const hashLink = el.querySelector('a[href*="/tx/"], a[href*="scan"], [class*="hash"], [class*="Hash"]');
      (hashLink ? (hashLink.parentElement || hashLink) : el).appendChild(btn);
    });
  }

  function watchForNewRows() {
    let debounce;
    new MutationObserver(() => {
      clearTimeout(debounce);
      debounce = setTimeout(injectRowButtons, 800);
    }).observe(document.body, { childList: true, subtree: true });
  }

  // ── Init ──────────────────────────────────────────────────────────────────
  function init() {
    console.log('[CTE] init() called, body=', !!document.body, 'existing panel=', !!document.getElementById(CTE_PANEL_ID));
    if (document.getElementById(CTE_PANEL_ID)) return;

    // FAB
    const fab = document.createElement('button');
    fab.id = 'cte-fab';
    fab.title = 'Crypto Tax Edge — AI TX Classifier';
    const fabImg = document.createElement('img');
    fabImg.src = 'data:image/png;base64,';
    fabImg.alt = 'Crypto Tax Edge';
    fab.appendChild(fabImg);
    if (!document.body) { console.error('[CTE] document.body is null!'); return; }
    try {
    document.body.appendChild(fab);

    const panel = createPanel();
    panel.style.display = 'none'; // hidden until FAB clicked
    document.body.appendChild(panel);

    let panelOpen = false;

    fab.addEventListener('click', () => {
      panelOpen = !panelOpen;
      panel.style.display = panelOpen ? 'block' : 'none';
      fab.classList.toggle('cte-fab-active', panelOpen);
      if (panelOpen) setTimeout(() => document.getElementById('cte-hash-input')?.focus(), 50);
    });

    document.getElementById('cte-minimize').addEventListener('click', () => {
      panelOpen = false;
      panel.style.display = 'none';
      fab.classList.remove('cte-fab-active');
    });


    // API key handled entirely in background.js

    document.getElementById('cte-analyze-btn').addEventListener('click', () => {
      const hash = document.getElementById('cte-hash-input').value.trim();
      if (hash) analyzeTx(hash);
    });

    document.getElementById('cte-hash-input').addEventListener('keydown', e => {
      if (e.key === 'Enter') {
        const h = e.target.value.trim();
        if (h) analyzeTx(h);
      }
    });

    setTimeout(injectRowButtons, 2000);
    watchForNewRows();
    console.log('[CTE] init() complete — FAB and panel injected');
    } catch(e) { console.error('[CTE] init() error:', e); }
  }

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init);
  else setTimeout(init, 1000);

})();
